#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float1 d = 0.002;
    float1 dx = ( GetBlur2(vUv + vec2(d,0)) - GetBlur2(vUv-vec2(d,0)) ).y;
    float1 dy = ( GetBlur2(vUv + vec2(0,d)) - GetBlur2(vUv-vec2(0,d)) ).y;
    vec2 my_uv = vUv - vec2(dx,dy)*0.02;

    ret.y = texture( sampler_fc_main, my_uv+floor(my_uv)).y;
    ret.y += (ret.y - GetBlur3(my_uv+floor(my_uv)).y)*.1;
    ret.y += 0.06;
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((my_uv.xyy*q27
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q29
                     );
if(ret.x> q21*q13         && ret.x<= q24*q11        )ret.y += (noise9).x*.5;
if(ret.y> q22*q11         && ret.y<= q25*q12        )ret.z += (noise9).y*.5;
if(ret.z> q23*q12         && ret.z<= q26*q13        )ret.x += (noise9).z*.5;
    ret.y = mix( ret.y, lum(ret).x, .1);

    ret.x = ret.y;
    ret.z = ret.y;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    vec3 main = texture( sampler_main, vUv ).xyz;
    float zoom = 1+( (vUv.x-vUv.y)*5 );
    float rot = sin(q5*.1+vRadius*2)*3;
    vec2 zcr = vec2(.5,.5);
    float n = 40;
    vec2 cr = .5;

//    vec3 moz = texture( sampler_main, cr ).xyz;
    vec2 newuv = vUv;

    ///////////////////rotation////////////////
    newuv = vUv - cr;
    float s = sin(rot);
    float c = cos(rot);
    newuv = vec2( (vUv.x-cr.x)*c-(vUv.y-cr.y)*s , (vUv.x-cr.x)*s+(vUv.y-cr.y)*c  );
    newuv = newuv + cr;
    ///////////////////rotation////////////////

    ///////////////////zoom////////////////
    newuv = newuv-zcr;
    newuv = newuv * zoom;
    newuv= newuv+zcr;
    ///////////////////zoom////////////////


    vec3 colorwarp = texture( sampler_main, newuv ).xyz *1.02;

    vec3 color = texture( sampler_rand03, newuv ).xyz;
    float mask = main.x*main.y*main.z > .9;
    vec2 cm = ((vUv*n-fract(vUv*n))%n)/n + .5/n;//vec2(((vUv.x*10)%10)/10,((vUv.y*10)%10)/10);
    vec3 moz = GetBlur1( cm )*(1-mask);

//ret = moz;
ret = ( (  (color+colorwarp)*.6*(mask)+main*(1-mask) ) );

vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((newuv.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q13         && ret.x<= q23*q11        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q11         && ret.y<= q22*q12        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q12         && ret.z<= q21*q13        )ret.y -= (noise9).z*.5;
    ret *= 1; //gamma;

  fragColor = ret;
}
